// Helper functions for creating mock data
function createMockEmail(id: string, subject: string): EmailMessage {
  return {
    id,
    threadId: `thread-${id}`,
    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: subject },
        { name: 'From', value: 'sender@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Date', value: new Date().toUTCString() },
      ],
      body: {
        data: Buffer.from('Test email body').toString('base64'),
      },
    },
    subject,
    from: {
      email: 'sender@example.com',
      name: 'Test Sender',
      raw: 'Test Sender <sender@example.com>',
    },
    to: [
      {
        email: 'recipient@example.com',
        name: 'Test Recipient',
        raw: 'Test Recipient <recipient@example.com>',
      },
    ],
    date: new Date(),
    bodyPlain: 'Test email body',
    isProcessed: false,
    processingPriority: 50,
  };
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function createMockClassificationResult(_emailId: string, confidence: number): any {
  return {
    selectedLabels: [
      {
        category: 'TEST_CATEGORY',
        subtype: 'test_subtype',
        confidence,
        score: confidence,
        isPrimary: true,
        labelOrder: 1,
        selectionRationale: 'Test rationale',
      },
    ],
    candidateScores: {
      TEST_CATEGORY: {
        score: confidence,
        confidence,
        decision: 'selected',
      },
    },
    selectionSummary: {
      totalLabels: 1,
      primaryCategory: 'TEST_CATEGORY',
      confidenceRange: [confidence, confidence],
      selectionMethod: 'multi_label',
      needsAi: false,
    },
    needsAiClassification: false,
    processingDurationMs: 150,
  };
}

