/**
 * Integration test setup
 *
 * Loads environment variables needed for database integration tests.
 * Falls back to reasonable defaults if environment is not fully configured.
 */

import dotenv from 'dotenv';
import path from 'path';

// Load environment from project root
const rootEnvPath = path.resolve(__dirname, '../../../../.env');
dotenv.config({ path: rootEnvPath });

// Ensure DATABASE_URL is set for Prisma
if (!process.env.DATABASE_URL) {
  // Construct DATABASE_URL from individual variables
  const host = process.env.POSTGRES_HOST || 'localhost';
  const port = process.env.POSTGRES_PORT || '5432';
  const user = process.env.PROJECT_DB_USER || 'gmail_app';
  const password = process.env.PROJECT_DB_PASS || '';
  const database = process.env.PROJECT_DB_NAME || 'gmail_automation';

  process.env.DATABASE_URL = `postgresql://${user}:${password}@${host}:${port}/${database}?schema=email`;
}

console.log('Integration test environment loaded');
console.log(`DATABASE_URL: ${process.env.DATABASE_URL?.replace(/:[^:@]+@/, ':****@')}`);

