/**
 * Valid Minimal Category Config Fixture
 *
 * Purpose: Provides a minimal but valid CategoryConfiguration object that passes Zod validation
 * for use in unit and integration tests.
 *
 * This fixture represents the full configuration wrapper including validation metadata,
 * whereas validMinimalProcessingConfig represents just the processingConfig section.
 *
 * Usage:
 * ```typescript
 * import { validMinimalCategoryConfig } from '@classification-engine/tests/fixtures/configs';
 *
 * const config = validMinimalCategoryConfig;
 * // Or customize:
 * const customConfig = {
 *   ...validMinimalCategoryConfig,
 *   processingConfig: {
 *     ...validMinimalCategoryConfig.processingConfig,
 *     version: 2,
 *   },
 * };
 * ```
 */

import { CategoryConfiguration } from '../../../src/types/category-configuration';
import { validMinimalProcessingConfig } from './valid-minimal-processing-config';

import { createHash } from 'crypto';

/**
 * Generate a SHA-256 hash for configuration validation
 *
 * @param content - Content to hash
 * @returns 64-character SHA-256 hash
 */
function generateConfigHash(content: string): string {
  return createHash('sha256').update(content).digest('hex');
}

/**
 * Minimal valid CategoryConfiguration for testing
 *
 * Includes all required fields per the CategoryConfigurationSchema from
 * packages/classification-engine/src/config/category-config-schema.ts
 */
export const validMinimalCategoryConfig: CategoryConfiguration = {
  // Metadata
  version: '1.0.0', // Semantic version format
  lastModified: new Date('2025-09-27T00:00:00.000Z'),
  hash: generateConfigHash(JSON.stringify(validMinimalProcessingConfig)),

  // Main processing configuration
  processingConfig: validMinimalProcessingConfig,

  // Validation metadata
  schemaVersion: '1.0.0',
  validationPassed: true,
  validationErrors: [],

  // Runtime optimization (empty arrays for test configs)
  compiledRules: [],
  attributeMatrix: {},
};

/**
 * Minimal valid CategoryConfiguration with one test category
 *
 * Useful for tests that need at least one category defined
 */
export const validMinimalCategoryConfigWithCategory: CategoryConfiguration = {
  ...validMinimalCategoryConfig,
  processingConfig: {
    ...validMinimalProcessingConfig,
    categorySignals: {
      TEST_CATEGORY: {
        hardAssertions: {
          subjectPrefixes: ['[TEST]'],
        },
        strongIndicators: {
          subjectContains: ['test'],
        },
      },
    },
    topLevelCategories: {
      TEST_CATEGORY: {
        description: 'Test category for unit tests',
        subtypes: {
          test_subtype: {
            description: 'Test subtype',
            derived: false,
            parallelSafe: true,
          },
        },
        aiFinalClassification: {
          categoryDescription: 'Test category',
          decisionCriteria: ['Contains test keywords'],
        },
      },
    },
    attributeRelevance: {
      RolesLegend: {
        CORE: 'Fundamental to category definition',
        PRIMARY_BOOST: 'Strong positive signal',
        SECONDARY_BOOST: 'Moderate positive signal',
        DISAMBIGUATOR: 'Resolves conflicts between categories',
        FILTER: 'Hard exclusion or inclusion',
        STRUCTURAL: 'Email structure indicators',
        DERIVED_LINK: 'Computed from other attributes',
        NEUTRAL: 'No impact on scoring',
      },
      TEST_CATEGORY: {
        categoryRoles: {},
      },
    },
  },
};

/**
 * Helper: Create a custom CategoryConfiguration by merging with minimal valid config
 *
 * @param overrides - Partial CategoryConfiguration to merge
 * @returns Complete valid CategoryConfiguration
 *
 * Example:
 * ```typescript
 * const config = createTestCategoryConfig({
 *   version: '2.0.0',
 *   processingConfig: {
 *     ...validMinimalProcessingConfig,
 *     version: 2,
 *   },
 * });
 * ```
 */
export function createTestCategoryConfig(overrides: Partial<CategoryConfiguration>): CategoryConfiguration {
  return {
    ...validMinimalCategoryConfig,
    ...overrides,
  };
}

/**
 * Valid Minimal Processing Config Fixture
 *
 * Purpose: Provides a minimal but valid ProcessingConfig object that passes Zod validation
 * for use in unit and integration tests.
 *
 * This fixture includes only the required fields and uses default values for optional fields.
 * All property names use camelCase to match the Zod schema requirements.
 *
 * Usage:
 * ```typescript
 * import { validMinimalProcessingConfig } from '@classification-engine/tests/fixtures/configs';
 *
 * const config = validMinimalProcessingConfig;
 * // Or customize:
 * const customConfig = {
 *   ...validMinimalProcessingConfig,
 *   settings: {
 *     ...validMinimalProcessingConfig.settings,
 *     aiRouting: {
 *       ...validMinimalProcessingConfig.settings.aiRouting,
 *       highConfidenceThreshold: 0.9,
 *     },
 *   },
 * };
 * ```
 */

import { ProcessingConfig } from '../../../src/types/category-configuration';

/**
 * Minimal valid ProcessingConfig for testing
 *
 * Includes all required fields per the CategoryConfigurationSchema from
 * packages/classification-engine/src/config/category-config-schema.ts
 */
export const validMinimalProcessingConfig: ProcessingConfig = {
  // Required: version and taxonomy notes
  version: 1,
  taxonomyNotes: 'Test configuration for unit tests',

  // Processing settings with all required subsections
  settings: {
    initialization: {
      applyHardAssertions: true,
      seedCategoryScores: true,
    },
    ruleScoring: {
      useLexicalPatterns: true,
      applySubtypeRules: true,
      boundedAggregation: true,
    },
    attributeProcessing: {
      detectSelfSent: true,
      resolveDomains: true,
      deriveContextFlags: true,
    },
    attributeInfluence: {
      applyBonuses: true,
      applyPenalties: true,
      enforceCaps: true,
    },
    disambiguation: {
      pairwiseAdjustments: true,
      confidenceGapThreshold: 0.1,
    },
    multiLabelSelection: {
      maxLabels: 3,
      highConfidenceThreshold: 0.8,
      mediumConfidenceThreshold: 0.5333,
      lowConfidenceThreshold: 0.2,
      secondaryLabelMinGap: 0.13333,
      allowedCombinations: [],
      strictCombinationMode: false,
