      ];

      gmailClient.setMockEmails(mockEmails);

      // Execute: Process batch - should continue despite individual failures
      const result = await emailProcessor.processBatch({ maxEmails: 10 });

      // Validate: Batch continues processing (all 3 processed, but some may have errors)
      expect(result.totalProcessed).toBe(3);
      expect(result.processingDurationMs).toBeGreaterThan(0);

      // Validate: At least some emails succeed OR all have errors captured
      // Integration reality: Some emails may fail due to AI classification issues
      expect(result.successCount + result.errorCount).toBe(3);

      // If there are errors, they should be captured in error details
      if (result.errorCount > 0) {
        expect(result.errors.length).toBe(result.errorCount);
      }
    });

    test('should return accurate metrics for empty batch', async () => {
      // Setup: No emails to process
      gmailClient.setMockEmails([]);

      // Execute
      const result = await emailProcessor.processBatch({ maxEmails: 10 });

      // Validate: Metrics reflect empty batch correctly
      expect(result.totalProcessed).toBe(0);
      expect(result.successCount).toBe(0);
      expect(result.errorCount).toBe(0);
      expect(result.averageEmailDurationMs).toBe(0);
      expect(result.errors).toHaveLength(0);

      // Validate: No persistence calls for empty batch
      expect(persistence.getSavedResults().size).toBe(0);
    });

    test('should propagate fatal Gmail API failures (FR-001)', async () => {
      // Setup: Gmail API failure
      gmailClient.setShouldFailFetch(true);

      // Execute & Validate: Fatal errors propagate
      await expect(emailProcessor.processBatch({ maxEmails: 10 })).rejects.toThrow(
        'Batch processing failed: Gmail API connection failed'
      );
    });

    test('should propagate fatal persistence failures (FR-008)', async () => {
